class FoodRatings {
    private Map<String, Integer> ratingMap;
    private Map<String, String> cuisineMap;

    public FoodRatings(String[] foods, String[] cuisines, int[] ratings) {
        ratingMap = new HashMap<>();
        cuisineMap = new HashMap<>();
        for (int i = 0; i < foods.length; i++) {
            ratingMap.put(foods[i], ratings[i]);
            cuisineMap.put(foods[i], cuisines[i]);
        }
    }

    public void changeRating(String food, int newRating) {
        ratingMap.put(food, newRating);
    }

    public String highestRated(String cuisine) {
        List<String> foods = new ArrayList<>(cuisineMap.keySet());
        foods.sort((a, b) -> {
            if (ratingMap.get(a).equals(ratingMap.get(b))) {
                return a.compareTo(b);
            }
            return ratingMap.get(a) - ratingMap.get(b);
        });
        for (String food : foods) {
            if (cuisineMap.get(food).equals(cuisine)) {
                return food;
            }
        }
        return "";
    }
}

